package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

public class CSVFormatTest {

    @Mock
    private Reader mockReader;

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        MockitoAnnotations.openMocks(this);
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testParse_WithValidReader_ReturnsCSVParser() throws IOException {
        CSVParser parser = csvFormat.parse(mockReader);
        assertNotNull(parser);
        assertSame(mockReader, parser.getReader());
        assertSame(csvFormat, parser.getFormat());
    }

    @Test
    public void testParse_WithNullReader_ThrowsNullPointerException() {
        assertThrows(NullPointerException.class, () -> {
            csvFormat.parse(null);
        });
    }
}
